import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.nio.file.Paths;

public class SecurePathTraversalExample {

    public static void main(String[] args) {
        String userInput = "../../../../../etc/passwd"; // User input with path traversal attempt

        String basePath = "/var/www/files/";
        String normalizedPath = Paths.get(basePath, userInput).normalize().toString(); // Normalize user input path

        if (!normalizedPath.startsWith(basePath)) {
            System.out.println("Invalid file path specified.");
            return;
        }

        File file = new File(normalizedPath);

        try {
            FileInputStream fis = new FileInputStream(file);
            byte[] data = new byte[(int) file.length()];
            fis.read(data);
            fis.close();

            System.out.println(new String(data));
        } catch (IOException e) {
            System.out.println("Error reading file: " + e.getMessage());
        }
    }
}

